-- Prompt Zero CSV import
-- Source: prompt-zero-export.csv
-- Rows: 13
-- Target user: ruben@8signal.com

DO $$
DECLARE
  target_user_id UUID;
BEGIN
  SELECT id INTO target_user_id FROM auth.users WHERE email = 'ruben@8signal.com' LIMIT 1;
  IF target_user_id IS NULL THEN
    RAISE EXCEPTION 'No auth.users row found for email ruben@8signal.com';
  END IF;

END $$;
